const { BREP } = api;

// Dish — round tray at the base
const dish = BREP.label(
  BREP.cylinder(25, 4),
  'dish'
);

// Dish lip — torus around the dish edge
const lip = BREP.label(
  BREP.torus(24, 1.2).translate([0, 0, 2.5]),
  'lip'
);

// Seed reservoir — revolved profile (wider at bottom, tapers to neck)
const reservoir = BREP.label(
  BREP.revolve([
    [0, 4], [18, 4], [16, 12], [10, 30], [10, 40], [0, 40]
  ]),
  'reservoir'
);

// Roof — gazebo cap (truncated cone)
const roof = BREP.label(
  BREP.cone(22, 4, 18).translate([0, 0, 42]),
  'roof'
);

// Roof spire — tiny pointed cone on top
const spire = BREP.label(
  BREP.cone(2, 0, 4).translate([0, 0, 60]),
  'spire'
);

// Perches — single horizontal cylinder + circularPattern around dish
const onePerch = BREP.cylinder(0.6, 8)
  .rotate(90, [1, 0, 0])
  .translate([26, 0, 6]);
const perches = BREP.label(
  BREP.circularPattern(onePerch, 6, { radius: 0, axis: [0, 0, 1] }),
  'perch'
);

// Hanging hook — small torus at the very top
const hook = BREP.label(
  BREP.torus(2, 0.5).translate([0, 0, 64]),
  'hook'
);

return BREP.fuseAll([dish, lip, reservoir, roof, spire, perches, hook]);

